mapper.select:
SELECT option_id, field_id, option_value,
        option_label, sort_order, status, create_by, create_time, update_by, update_time, remark
        FROM ticket_custom_field_option WHERE option_id=#{optionId}

mapper.update:
UPDATE ticket_custom_field_option SET option_label=#{optionLabel},
        sort_order=#{sortOrder}, status=#{status}, update_by=#{updateBy}, update_time=#{updateTime}, remark=#{remark}
        WHERE option_id=#{optionId} AND field_id=#{fieldId}
